+
+    function guard_with_startup_progress(fn) {
+        return function () {
+            try {
+                fn.apply(this, arguments);
+            } catch (err) {
+                if (err instanceof TypeError) {
+                    show_err_msg('Balancer error: ' + err);
+                }
+            }
+        };
+    }
+
